INSERT OR IGNORE INTO commands (id, intent, tags, os, commands_json, summary, source, created_at) VALUES ('97b3fcf8', 'initialize a new git repository', '["git", "init", "setup", "version control", "new project"]', 'all', '[{"command": "git init", "explanation": "Creates a new empty git repository in the current directory"}, {"command": "git add .", "explanation": "Stages all existing files for the first commit"}, {"command": "git commit -m \"{{COMMIT_MESSAGE}}\"", "explanation": "Creates the first commit with your message"}]', 'Initialize a new git repository and make the first commit', 'seed', '2026-05-15T15:45:27.950198');
INSERT OR IGNORE INTO commands (id, intent, tags, os, commands_json, summary, source, created_at) VALUES ('654d9c28', 'configure git username and email', '["git", "config", "username", "email", "identity", "setup"]', 'all', '[{"command": "git config --global user.name \"{{YOUR_NAME}}\"", "explanation": "Sets your name for all git commits on this machine"}, {"command": "git config --global user.email \"{{YOUR_EMAIL}}\"", "explanation": "Sets your email for all git commits on this machine"}]', 'Configure your global git identity', 'seed', '2026-05-15T15:45:27.950198');
INSERT OR IGNORE INTO commands (id, intent, tags, os, commands_json, summary, source, created_at) VALUES ('6b6d6469', 'create and switch to a new git branch', '["git", "branch", "checkout", "feature branch", "new branch"]', 'all', '[{"command": "git checkout -b {{BRANCH_NAME}}", "explanation": "Creates a new branch and switches to it immediately"}]', 'Create a new git branch and switch to it', 'seed', '2026-05-15T15:45:27.950198');
INSERT OR IGNORE INTO commands (id, intent, tags, os, commands_json, summary, source, created_at) VALUES ('181dd022', 'merge a branch into main', '["git", "merge", "main", "branch", "pull request"]', 'all', '[{"command": "git checkout main", "explanation": "Switch to the main branch first"}, {"command": "git merge {{BRANCH_NAME}}", "explanation": "Merge the specified branch into main"}, {"command": "git push origin main", "explanation": "Push the merged result to the remote repository"}]', 'Merge a feature branch into main and push to remote', 'seed', '2026-05-15T15:45:27.950198');
INSERT OR IGNORE INTO commands (id, intent, tags, os, commands_json, summary, source, created_at) VALUES ('e3e79e64', 'initialize a react project', '["react", "create-react-app", "frontend", "javascript", "npm"]', 'all', '[{"command": "npx create-react-app {{PROJECT_NAME}}", "explanation": "Creates a new React project with all configuration included"}, {"command": "cd {{PROJECT_NAME}}", "explanation": "Enter the newly created project folder"}, {"command": "npm start", "explanation": "Start the development server on localhost:3000"}]', 'Create a new React project and start the development server', 'seed', '2026-05-15T15:45:27.950198');
INSERT OR IGNORE INTO commands (id, intent, tags, os, commands_json, summary, source, created_at) VALUES ('ddb6bc72', 'initialize a react project with typescript', '["react", "typescript", "tsx", "frontend", "npm", "create-react-app"]', 'all', '[{"command": "npx create-react-app {{PROJECT_NAME}} --template typescript", "explanation": "Creates a new React project with TypeScript pre-configured"}, {"command": "cd {{PROJECT_NAME}}", "explanation": "Enter the project folder"}, {"command": "npm start", "explanation": "Start the development server"}]', 'Create a new React + TypeScript project', 'seed', '2026-05-15T15:45:27.950198');
INSERT OR IGNORE INTO commands (id, intent, tags, os, commands_json, summary, source, created_at) VALUES ('b6e5ab21', 'install tailwind css', '["tailwind", "css", "styling", "postcss", "npm"]', 'all', '[{"command": "npm install -D tailwindcss postcss autoprefixer", "explanation": "Install Tailwind CSS and its required build tools"}, {"command": "npx tailwindcss init -p", "explanation": "Generate tailwind.config.js and postcss.config.js"}]', 'Add Tailwind CSS to an existing project', 'seed', '2026-05-15T15:45:27.950198');
INSERT OR IGNORE INTO commands (id, intent, tags, os, commands_json, summary, source, created_at) VALUES ('7739a5ae', 'create a python virtual environment', '["python", "venv", "virtualenv", "pip", "environment", "isolate"]', 'all', '[{"command": "python3 -m venv venv", "explanation": "Creates a virtual environment in a folder called venv"}, {"command": "source venv/bin/activate", "explanation": "Activates the virtual environment"}, {"command": "pip install --upgrade pip", "explanation": "Upgrades pip to the latest version inside the environment"}]', 'Create and activate a Python virtual environment', 'seed', '2026-05-15T15:45:27.950198');
INSERT OR IGNORE INTO commands (id, intent, tags, os, commands_json, summary, source, created_at) VALUES ('e07b70ae', 'install python packages from requirements file', '["python", "pip", "requirements", "install", "dependencies"]', 'all', '[{"command": "pip install -r requirements.txt", "explanation": "Installs all packages listed in requirements.txt"}]', 'Install all Python dependencies from requirements.txt', 'seed', '2026-05-15T15:45:27.950198');
INSERT OR IGNORE INTO commands (id, intent, tags, os, commands_json, summary, source, created_at) VALUES ('545e3095', 'create a new node project', '["node", "npm", "init", "javascript", "package.json", "backend"]', 'all', '[{"command": "mkdir {{PROJECT_NAME}} && cd {{PROJECT_NAME}}", "explanation": "Create and enter the project folder"}, {"command": "npm init -y", "explanation": "Initialize npm with default settings, creates package.json"}]', 'Create a new Node.js project', 'seed', '2026-05-15T15:45:27.950198');
INSERT OR IGNORE INTO commands (id, intent, tags, os, commands_json, summary, source, created_at) VALUES ('f195b873', 'install postgresql on ubuntu', '["postgresql", "postgres", "database", "install", "apt", "sql"]', 'ubuntu', '[{"command": "sudo apt update", "explanation": "Refresh the package list before installing"}, {"command": "sudo apt install -y postgresql postgresql-contrib", "explanation": "Install PostgreSQL and additional useful utilities"}, {"command": "sudo systemctl start postgresql", "explanation": "Start the PostgreSQL service"}, {"command": "sudo systemctl enable postgresql", "explanation": "Make PostgreSQL start automatically on system boot"}]', 'Install and start PostgreSQL on Ubuntu', 'seed', '2026-05-15T15:45:27.950198');
INSERT OR IGNORE INTO commands (id, intent, tags, os, commands_json, summary, source, created_at) VALUES ('f10a8a05', 'install postgresql on macos', '["postgresql", "postgres", "database", "install", "brew", "homebrew"]', 'macos', '[{"command": "brew install postgresql@15", "explanation": "Install PostgreSQL version 15 via Homebrew"}, {"command": "brew services start postgresql@15", "explanation": "Start PostgreSQL and enable it on login"}]', 'Install and start PostgreSQL on macOS', 'seed', '2026-05-15T15:45:27.950198');
