INSERT OR IGNORE INTO commands (id, intent, tags, os, commands_json, summary, source, created_at) VALUES ('0f1b5aa7', 'stop docker compose containers', '["docker", "compose", "stop", "down", "containers"]', 'all', '[{"command": "docker compose down", "explanation": "Stop and remove all containers defined in docker-compose.yml"}]', 'Stop all Docker Compose containers', 'seed', '2026-05-15T15:45:27.950198');
INSERT OR IGNORE INTO commands (id, intent, tags, os, commands_json, summary, source, created_at) VALUES ('7cb834f4', 'generate ssh key pair', '["ssh", "key", "keygen", "github", "authentication", "security"]', 'all', '[{"command": "ssh-keygen -t ed25519 -C \"{{YOUR_EMAIL}}\"", "explanation": "Generate a new SSH key using the modern ed25519 algorithm"}, {"command": "eval \"$(ssh-agent -s)\"", "explanation": "Start the SSH agent in the background"}, {"command": "ssh-add ~/.ssh/id_ed25519", "explanation": "Register your new key with the SSH agent"}, {"command": "cat ~/.ssh/id_ed25519.pub", "explanation": "Print your public key \u2014 copy this and paste it into GitHub settings"}]', 'Generate an SSH key pair ready for use with GitHub', 'seed', '2026-05-15T15:45:27.950198');
INSERT OR IGNORE INTO commands (id, intent, tags, os, commands_json, summary, source, created_at) VALUES ('1a7e189b', 'find process using a port and kill it', '["port", "process", "kill", "lsof", "network", "pid"]', 'ubuntu', '[{"command": "sudo lsof -i :{{PORT_NUMBER}}", "explanation": "Show which process is currently using the specified port"}, {"command": "sudo kill -9 $(sudo lsof -t -i :{{PORT_NUMBER}})", "explanation": "Forcefully kill the process using the port", "warning": "This terminates the process immediately without cleanup \u2014 save your work first"}]', 'Find and kill the process running on a specific port', 'seed', '2026-05-15T15:45:27.950198');
INSERT OR IGNORE INTO commands (id, intent, tags, os, commands_json, summary, source, created_at) VALUES ('eb4a1da1', 'compress a folder to tar gz', '["tar", "compress", "archive", "gz", "zip", "backup", "folder"]', 'all', '[{"command": "tar -czf {{ARCHIVE_NAME}}.tar.gz {{FOLDER_NAME}}", "explanation": "Compress the folder into a .tar.gz archive"}]', 'Create a compressed .tar.gz archive from a folder', 'seed', '2026-05-15T15:45:27.950198');
